for t = min_gray_level:max_gray_level
    % 计算背景与前景的像素总数
    background_pixels = sum(histogram(1:t-min_gray_level+1));
    foreground_pixels = sum(histogram(t-min_gray_level+2:end));

    % 计算背景和前景的概率
